// Fallback si le LLM n'est pas disponible
const text = $input.all()[0].json.text;
const regexResult = {
  numero: text.match(/Facture[\s:N°]*([A-Za-z0-9-]+)/)?.[1] || null,
  date: text.match(/Date[\s:]*([0-9]{2}\/[0-9]{2}\/[0-9]{4})/)?.[1] || null,
  client: text.match(/Client[\s:]*([A-Za-z0-9\s]+)/)?.[1] || null,
  montantHT: text.match(/Montant HT[\s:]*([0-9,.]+)/)?.[1] ? parseFloat(text.match(/Montant HT[\s:]*([0-9,.]+)/)[1].replace(',', '.').trim()) : null,
  tva: text.match(/TVA[\s(20%)]*([0-9,.]+)/)?.[1] ? parseFloat(text.match(/TVA[\s(20%)]*([0-9,.]+)/)[1].replace(',', '.').trim()) : null,
  montantTTC: text.match(/Montant TTC[\s:]*([0-9,.]+)/)?.[1] ? parseFloat(text.match(/Montant TTC[\s:]*([0-9,.]+)/)[1].replace(',', '.').trim()) : null
};

// Si le LLM a répondu, on utilise sa réponse, sinon on utilise les regex
const llmResponse = $input.all()[1]?.json?.response;
return llmResponse ? JSON.parse(llmResponse) : regexResult;
